import React, { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { authService } from "../services";
import Sidebar from "../components/Sidebar";
import { getAdminMenuItems } from "../config/menuConfig";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";
import { FiBox, FiUsers, FiCheck, FiClock } from "react-icons/fi";
import "../styles/Dashboard.css";

// Sample data
const loadDataByDay = [
  { day: "Mon", loads: 24, completed: 20 },
  { day: "Tue", loads: 34, completed: 28 },
  { day: "Wed", loads: 28, completed: 24 },
  { day: "Thu", loads: 42, completed: 35 },
  { day: "Fri", loads: 38, completed: 32 },
  { day: "Sat", loads: 32, completed: 28 },
  { day: "Sun", loads: 18, completed: 16 },
];

const recentLoadsTable = [
  {
    id: 1,
    loadId: "#L001",
    origin: "New York",
    destination: "Boston",
    status: "Completed",
    distance: "215 km",
    date: "2024-02-20",
  },
  {
    id: 2,
    loadId: "#L002",
    origin: "Boston",
    destination: "Philadelphia",
    status: "In Progress",
    distance: "385 km",
    date: "2024-02-21",
  },
  {
    id: 3,
    loadId: "#L003",
    origin: "Philadelphia",
    destination: "Washington DC",
    status: "Pending",
    distance: "225 km",
    date: "2024-02-22",
  },
  {
    id: 4,
    loadId: "#L004",
    origin: "Washington DC",
    destination: "Atlanta",
    status: "Completed",
    distance: "635 km",
    date: "2024-02-22",
  },
  {
    id: 5,
    loadId: "#L005",
    origin: "Atlanta",
    destination: "Miami",
    status: "In Progress",
    distance: "1100 km",
    date: "2024-02-23",
  },
];

const getStatusColor = (status) => {
  const colors = {
    Completed: "#10b981",
    "In Progress": "#3b82f6",
    Pending: "#f59e0b",
    Cancelled: "#ef4444",
  };
  return colors[status] || "#6b7280";
};

const StatPanel = ({ icon: Icon, title, value, subtitle, color }) => (
  <div className="stat-panel">
    <div className="stat-icon" style={{ backgroundColor: `${color}20` }}>
      <Icon size={28} style={{ color }} />
    </div>
    <div className="stat-info">
      <p className="stat-title">{title}</p>
      <h3 className="stat-value">{value}</h3>
      <p className="stat-subtitle">{subtitle}</p>
    </div>
  </div>
);

const AdminDashboard = () => {
  const user = authService.getCurrentUser();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const handleLogout = () => {
    authService.logout();
    navigate("/admin/login");
  };

  const menuItems = getAdminMenuItems(navigate);

  const isActive = (path) => location.pathname === path;

  return (
    <div className="dashboard-container">
      <Sidebar
        sidebarOpen={sidebarOpen}
        setSidebarOpen={setSidebarOpen}
        menuItems={menuItems}
        isActive={isActive}
        handleLogout={handleLogout}
        sidebarTitle="🛡️ Admin"
      />

      {/* Main Content */}
      <main className="dashboard-main">
        <div className="dashboard-content">
          {/* Statistics Panels */}
          <div className="stats-grid">
            <StatPanel
              icon={FiBox}
              title="Total Loads"
              value="268"
              subtitle="+12 this week"
              color="#3b82f6"
            />
            <StatPanel
              icon={FiCheck}
              title="Completed"
              value="183"
              subtitle="68% completion rate"
              color="#10b981"
            />
            <StatPanel
              icon={FiClock}
              title="In Progress"
              value="32"
              subtitle="12% of active loads"
              color="#f59e0b"
            />
            <StatPanel
              icon={FiUsers}
              title="Active Users"
              value="45"
              subtitle="+3 new users"
              color="#8b5cf6"
            />
          </div>

          {/* Charts Section */}
          <div className="charts-grid">
            {/* Bar Chart - Loads Analytics */}
            <div className="chart-panel full-width">
              <div className="chart-header">
                <h3>Load Analytics</h3>
                <span className="chart-subtitle">Weekly comparison</span>
              </div>
              <ResponsiveContainer width="100%" height={300}>
                <BarChart data={loadDataByDay}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="day" />
                  <YAxis />
                  <Tooltip />
                  <Legend />
                  <Bar
                    dataKey="loads"
                    fill="#3b82f6"
                    name="Total Loads"
                    radius={[8, 8, 0, 0]}
                  />
                  <Bar
                    dataKey="completed"
                    fill="#10b981"
                    name="Completed Loads"
                    radius={[8, 8, 0, 0]}
                  />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          {/* Data Table Section */}
          <div className="table-panel">
            <div className="table-header">
              <h3>Recent Loads</h3>
              <button
                onClick={() => navigate("/loads")}
                className="btn-view-all"
              >
                View All →
              </button>
            </div>

            <div className="table-responsive">
              <table className="data-table">
                <thead>
                  <tr>
                    <th>Load ID</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Distance</th>
                    <th>Status</th>
                    <th>Date</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {recentLoadsTable.map((load) => (
                    <tr key={load.id}>
                      <td className="load-id">{load.loadId}</td>
                      <td>{load.origin}</td>
                      <td>{load.destination}</td>
                      <td>{load.distance}</td>
                      <td>
                        <span
                          className="status-badge"
                          style={{
                            backgroundColor: getStatusColor(load.status),
                          }}
                        >
                          {load.status}
                        </span>
                      </td>
                      <td>{load.date}</td>
                      <td>
                        <button
                          className="btn-edit"
                          onClick={() => navigate(`/load/${load.id}`)}
                        >
                          View
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default AdminDashboard;
